namespace sv_9bb1dc165eda4e97b0d43a7fa88dc0dc.Client.Models;

public class Shipment
{
    public required string TrackingNumber { get; set; }
    public required string Status { get; set; }
    public required string Location { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public List<StatusUpdate> StatusUpdates { get; set; } = [];
}

public class StatusUpdate
{
    public required string Description { get; set; }
    public required string Location { get; set; }
    public DateTime Timestamp { get; set; }
}

using sv_9bb1dc165eda4e97b0d43a7fa88dc0dc.Client.Models;

namespace sv_9bb1dc165eda4e97b0d43a7fa88dc0dc.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_9bb1dc165eda4e97b0d43a7fa88dc0dc.Client.Models;

namespace sv_9bb1dc165eda4e97b0d43a7fa88dc0dc.Client.Services;

public class ClientShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var shipment = await httpClient.GetFromJsonAsync<Shipment>(
            $"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        return shipment ?? throw new InvalidOperationException("Shipment not found.");
    }
}

using sv_9bb1dc165eda4e97b0d43a7fa88dc0dc.Client.Models;
using sv_9bb1dc165eda4e97b0d43a7fa88dc0dc.Client.Services;

namespace sv_9bb1dc165eda4e97b0d43a7fa88dc0dc.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> Shipments = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = DateTime.Today.AddDays(2),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "New York, NY", Timestamp = DateTime.Today.AddDays(-3) },
                new StatusUpdate { Description = "Arrived at sorting facility", Location = "Philadelphia, PA", Timestamp = DateTime.Today.AddDays(-2) },
                new StatusUpdate { Description = "In transit", Location = "Chicago, IL", Timestamp = DateTime.Today.AddDays(-1) },
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = DateTime.Today.AddDays(-1),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = DateTime.Today.AddDays(-5) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = DateTime.Today.AddDays(-3) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = DateTime.Today.AddDays(-1) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = DateTime.Today.AddDays(-1).AddHours(14) },
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = DateTime.Today.AddDays(5),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Dallas, TX", Timestamp = DateTime.Today },
            ]
        },
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (Shipments.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_9bb1dc165eda4e97b0d43a7fa88dc0dc.Client.Models
@using sv_9bb1dc165eda4e97b0d43a7fa88dc0dc.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracking> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@(_shipment.EstimatedDelivery?.ToString("MMMM d, yyyy") ?? "N/A")</dd>
        </dl>

        @if (_shipment.StatusUpdates.Count > 0)
        {
            <h3>Tracking History</h3>
            <ul class="status-updates">
                @foreach (var update in _shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
                {
                    <li>
                        <strong>@update.Timestamp.ToString("MMM d, yyyy h:mm tt")</strong> —
                        @update.Description (@update.Location)
                    </li>
                }
            </ul>
        }
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override Task OnParametersSetAsync()
    {
        return LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any previous in-flight request
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation or disposal triggered cancellation — no action needed.
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || ex.CancellationToken != ct)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private void RetryLoad()
    {
        _ = LoadShipmentAsync();
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

